// packages/database/src/db/schema/workflow-app.ts
// Drizzle table: workflowApp (generated by scripts/split-schema.ts)

import {
  pgTable,
  uniqueIndex,
  index,
  text,
  boolean,
  timestamp,
  jsonb,
  integer,
  type AnyPgColumn,
  workflowShareAccessMode,
} from './_shared'
import { createId } from '@paralleldrive/cuid2'

import { User } from './user'
import { Workflow } from './workflow'
import { Organization } from './organization'

/**
 * Icon configuration for shared workflow
 */
export interface WorkflowShareIcon {
  iconId: string
  color: string
}

/**
 * Configuration for shared workflow
 */
export interface WorkflowShareConfig {
  /** Custom title (overrides workflow name) */
  title?: string
  /** Custom description */
  description?: string
  /** About section text for the public page */
  about?: string
  /** Custom logo URL */
  logoUrl?: string
  /** Custom brand name */
  brandName?: string
  /** Hide "Powered by Auxx" branding */
  hideBranding?: boolean
  /** Show workflow canvas preview */
  showWorkflowPreview?: boolean
  /** Show input form for manual trigger */
  showInputForm?: boolean
  /** Custom submit button text */
  submitButtonText?: string
  /** Custom success message */
  successMessage?: string
  /** Max concurrent executions */
  maxConcurrentRuns?: number
  /** Show detailed workflow execution events (all nodes) - default false for privacy */
  showWorkflowDetails?: boolean
}

/**
 * Rate limit configuration for shared workflow
 */
export interface WorkflowShareRateLimitConfig {
  enabled: boolean
  /** Max requests per window */
  maxRequests: number
  /** Window in milliseconds */
  windowMs: number
  /** Per-user vs global rate limiting */
  perUser?: boolean
}

/** Drizzle table for workflowApp */
export const WorkflowApp = pgTable(
  'WorkflowApp',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    organizationId: text()
      .notNull()
      .references((): AnyPgColumn => Organization.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    name: text().notNull(),
    description: text(),
    enabled: boolean().default(true).notNull(),
    createdById: text().references((): AnyPgColumn => User.id, { onUpdate: 'cascade' }),
    isPublic: boolean().default(false).notNull(),
    isUniversal: boolean().default(false).notNull(),
    workflowId: text().references((): AnyPgColumn => Workflow.id, { onUpdate: 'cascade' }),
    createdAt: timestamp({ precision: 3 }).defaultNow().notNull(),
    updatedAt: timestamp({ precision: 3 }).notNull(),
    draftWorkflowId: text().references((): AnyPgColumn => Workflow.id, { onUpdate: 'cascade' }),

    // Share configuration columns
    /** Unique URL identifier for sharing (null = sharing not configured) */
    shareToken: text().unique(),
    /** Whether web/browser access is enabled via public URL */
    webEnabled: boolean().default(false).notNull(),
    /** Whether programmatic API access is enabled */
    apiEnabled: boolean().default(false).notNull(),
    /** Icon with iconId and color for public page */
    icon: jsonb().$type<WorkflowShareIcon>(),
    /** Access mode for web access (public or organization) */
    accessMode: workflowShareAccessMode().default('public'),
    /** Share configuration */
    config: jsonb().$type<WorkflowShareConfig>(),
    /** Rate limit configuration */
    rateLimit: jsonb().$type<WorkflowShareRateLimitConfig>(),
    /** Total runs via public share */
    totalRuns: integer().default(0).notNull(),
    /** Last run timestamp via public share */
    lastRunAt: timestamp({ precision: 3 }),
  },
  (table) => [
    uniqueIndex('WorkflowApp_draftWorkflowId_key').using(
      'btree',
      table.draftWorkflowId.asc().nullsLast()
    ),
    index('WorkflowApp_organizationId_enabled_idx').using(
      'btree',
      table.organizationId.asc().nullsLast(),
      table.enabled.asc().nullsLast()
    ),
    index('WorkflowApp_organizationId_isPublic_idx').using(
      'btree',
      table.organizationId.asc().nullsLast(),
      table.isPublic.asc().nullsLast()
    ),
    uniqueIndex('WorkflowApp_workflowId_key').using('btree', table.workflowId.asc().nullsLast()),
    uniqueIndex('WorkflowApp_shareToken_key').using('btree', table.shareToken.asc().nullsLast()),
    index('WorkflowApp_webEnabled_idx').using('btree', table.webEnabled.asc().nullsLast()),
    index('WorkflowApp_apiEnabled_idx').using('btree', table.apiEnabled.asc().nullsLast()),
  ]
)
